import java.util.Scanner;

public class Main {
  public static void main(String[] args) {
    // Create a Scanner object to read input from the standard input stream
    Scanner stdIn = new Scanner(System.in);
    try {
      // Read the first integer input which represents the count of +1 values
      int oneNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (oneNum < 0) return;

      // Read the second integer input which represents the count of 0 values
      int zeroNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (zeroNum < 0) return;

      // Read the third integer input which represents the count of -1 values
      int minusOneNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (minusOneNum < 0) return;

      // Read the fourth integer input which represents the number of selections
      int selectNum = stdIn.nextInt();
      // Validate the selectNum input:
      // - It must be at least 1
      // - The total number of available numbers must be at least selectNum
      // - The total number of available numbers must not exceed 2 billion
      if (selectNum < 1 || (oneNum + zeroNum + minusOneNum) < selectNum || (oneNum + zeroNum + minusOneNum) > 2 * Math.pow(10, 9)) return;

      // Initialize maxValue to store the maximum sum possible
      int maxValue = 0;
      // Initialize restSelect to track the remaining selections
      int restSelect = selectNum;

      // Process the +1 values
      if (restSelect != 0) {
        // If the number of +1 values is less than or equal to the remaining selections
        if (oneNum <= restSelect) {
          // Add +1 for each available +1 value
          for (int oneCnt = 0; oneCnt < oneNum; oneCnt++) {
            maxValue++;
          }
          // Decrease the remaining selections by the number of +1 values used
          restSelect -= oneNum;
        } else {
          // If there are more +1 values than needed, use only the required amount
          for (int oneCnt = 0; oneCnt < restSelect; oneCnt++) {
            maxValue++;
          }
          // All selections are used up
          restSelect = 0;
        }
      }

      // Process the 0 values
      if (restSelect != 0) {
        // If the number of 0 values is less than or equal to the remaining selections
        if (zeroNum <= restSelect) {
          // Simply decrease the remaining selections by the number of 0 values used
          restSelect -= zeroNum;
        } else {
          // If there are more 0 values than needed, use only the required amount
          restSelect -= restSelect;
        }
      }

      // Process the -1 values
      if (restSelect != 0) {
        // If the number of -1 values is less than or equal to the remaining selections
        if (minusOneNum <= restSelect) {
          // Subtract 1 for each available -1 value
          for (int minusOneCnt = 0; minusOneCnt < minusOneNum; minusOneCnt++) {
            maxValue--;
          }
          // Decrease the remaining selections by the number of -1 values used
          restSelect -= minusOneNum;
        } else {
          // If there are more -1 values than needed, use only the required amount
          for (int minusOneCnt = 0; minusOneCnt < restSelect; minusOneCnt++) {
            maxValue--;
          }
          // All selections are used up
          restSelect -= restSelect;
        }
      }

      // Output the maximum value calculated
      System.out.println(maxValue);
    } catch (Exception e) {
      // Print the stack trace if an exception occurs
      e.printStackTrace();
    } finally {
      // Close the Scanner object to free up resources
      stdIn.close();
    }
  }
}

