public class Main {

    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read two integers A and B from the input
        int A = sc.nextInt();
        int B = sc.nextInt();

        // Read a string S from the input
        String S = sc.next();

        // Convert the string S into a character array for easy manipulation
        char[] ans = S.toCharArray();

        // Initialize two flags A1 and A2 to zero
        // These flags will be used to determine if the string S meets certain conditions
        int A1 = 0;
        int A2 = 0;

        // Check if the character at position A in the string S is a hyphen ('-')
        if ('-' == S.charAt(A)) {
            // Loop through the first A characters of the string
            for (int i = 0; A > i; i++) {
                // Check if the current character is a digit (0-9)
                if (ans[i] == '0' || ans[i] == '1' || ans[i] == '2' || ans[i] == '3' || ans[i] == '4' || ans[i] == '5' || ans[i] == '6' || ans[i] == '7' || ans[i] == '8' || ans[i] == '9') {
                    // If it is a digit, continue to the next character
                } else {
                    // If it is not a digit, set A1 to 1 and break the loop
                    A1 = 1;
                    break;
                }
            }
            // Loop through the next B characters after the hyphen
            for (int j = 0; B > j; j++) {
                // Check if the current character is a digit (0-9)
                if (ans[A + 1 + j] == '0' || ans[j + A + 1] == '1' || ans[j + A + 1] == '2' || ans[j + A + 1] == '3' || ans[j + A + 1] == '4' || ans[j + A + 1] == '5' || ans[j + A + 1] == '6' || ans[j + A + 1] == '7' || ans[j + A + 1] == '8' || ans[j + A + 1] == '9') {
                    // If it is a digit, continue to the next character
                } else {
                    // If it is not a digit, set A2 to 1 and break the loop
                    A2 = 1;
                    break;
                }
            }
        } else {
            // If the character at position A is not a hyphen, set both A1 and A2 to 1
            A1 = 1;
            A2 = 1;
        }

        // Check the values of A1 and A2 to determine the output
        if (A1 == 0 && A2 == 0) {
            // If both A1 and A2 are zero, print "Yes"
            System.out.println("Yes");
        } else {
            // If either A1 or A2 is not zero, print "No"
            System.out.println("No");
        }
    }
}

